// Helper to get member by ID
export const getMemberById = (id) => familyMembers.find((m) => m.id === id)

// Helper to get members by generation
export const getMembersByGeneration = (gen) =>
  familyMembers.filter((m) => m.generation === gen)

// Helper to get living members
export const getLivingMembers = () => familyMembers.filter((m) => m.isAlive)

// Helper to get Lê bloodline members (born into family, not married in)
export const getBloodlineMembers = () =>
  familyMembers.filter((m) => m.fatherId !== null || m.motherId !== null || m.generation <= 1)